import React from 'react';
import { PaginatedTable } from './PaginatedTable';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '36rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Paginated Records</h1>
      <PaginatedTable apiUrl="/api/records" limit={10} />
    </div>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface Record {
  id: number;
  name: string;
  email: string;
  status: string;
}

interface PaginatedTableProps {
  apiUrl: string;
  limit: number;
}

// TODO: Implement paginated data fetching
// 1. Fetch page on mount and on page change
// 2. Cache fetched pages
// 3. Show loading overlay without removing data
// 4. Page navigation with prev/next/page buttons

export const PaginatedTable: React.FC<PaginatedTableProps> = ({ apiUrl, limit }) => {
  const [rows, setRows] = useState<Record[]>([]);
  const [page, setPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  // TODO: page cache

  const totalPages = Math.ceil(totalCount / limit) || 1;

  // TODO: fetchPage function
  // TODO: useEffect to fetch on page change

  const rangeStart = (page - 1) * limit + 1;
  const rangeEnd = Math.min(page * limit, totalCount);

  return (
    <div className="ptable">
      <div className="ptable__info">
        <span data-testid="page-info">
          {totalCount > 0 ? `${rangeStart}–${rangeEnd} of ${totalCount}` : 'No records'}
        </span>
      </div>

      <div className="ptable__wrapper">
        {isLoading && <div data-testid="loading-overlay" className="ptable__overlay" />}
        <table className="ptable__table">
          <thead>
            <tr>
              <th>Name</th>
              <th>Email</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody data-testid="table-body">
            {rows.map((row, i) => (
              <tr key={row.id} data-testid={`row-${i}`}>
                <td>{row.name}</td>
                <td>{row.email}</td>
                <td><span className={`ptable__status ptable__status--${row.status}`}>{row.status}</span></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="ptable__nav">
        <button data-testid="prev-btn" className="ptable__btn" disabled={page <= 1}>
          Previous
        </button>
        {/* TODO: Page number buttons */}
        <button data-testid="next-btn" className="ptable__btn" disabled={page >= totalPages}>
          Next
        </button>
      </div>
    </div>
  );
};

.ptable {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.ptable__info {
  font-size: 0.8125rem;
  color: #6b7280;
}

.ptable__wrapper {
  position: relative;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  overflow: hidden;
}

.ptable__overlay {
  position: absolute;
  inset: 0;
  background: rgba(255,255,255,0.6);
  z-index: 10;
  pointer-events: none;
}

.ptable__table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.875rem;
}

.ptable__table thead {
  background: #f9fafb;
}

.ptable__table th {
  padding: 0.5rem 0.75rem;
  text-align: left;
  font-weight: 500;
  color: #374151;
  border-bottom: 1px solid #e5e7eb;
}

.ptable__table td {
  padding: 0.5rem 0.75rem;
  color: #4b5563;
  border-bottom: 1px solid #f3f4f6;
}

.ptable__status {
  font-size: 0.75rem;
  padding: 0.125rem 0.5rem;
  border-radius: 9999px;
}

.ptable__status--active { background: #dcfce7; color: #16a34a; }
.ptable__status--inactive { background: #fef3c7; color: #d97706; }
.ptable__status--banned { background: #fecaca; color: #dc2626; }

.ptable__nav {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  justify-content: center;
}

.ptable__btn {
  padding: 0.375rem 0.625rem;
  border: 1px solid #d1d5db;
  border-radius: 0.375rem;
  background: white;
  font-size: 0.8125rem;
  cursor: pointer;
}

.ptable__btn:hover:not(:disabled) {
  background: #f3f4f6;
}

.ptable__btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.ptable__btn--active {
  background: #3b82f6;
  color: white;
  border-color: #3b82f6;
}

