import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

const makePage = (page: number, limit: number) => ({
  data: Array.from({ length: limit }, (_, i) => ({
    id: (page - 1) * limit + i + 1,
    name: `User ${(page - 1) * limit + i + 1}`,
    email: `user${(page - 1) * limit + i + 1}@test.com`,
    status: 'active',
  })),
  totalCount: 50,
});

let fetchMock: jest.Mock;

beforeEach(() => {
  fetchMock = jest.fn((url: string) => {
    const params = new URL(url, 'http://localhost').searchParams;
    const page = parseInt(params.get('page') || '1');
    const limit = parseInt(params.get('limit') || '10');
    return Promise.resolve({
      ok: true,
      json: () => Promise.resolve(makePage(page, limit)),
    });
  });
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.restoreAllMocks();
});

import App from './App';

describe('Paginated Data Table', () => {
  it('fetches first page on mount', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('row-0')).toBeInTheDocument();
    });
  });

  it('shows page info', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('page-info')).toHaveTextContent('1–10 of 50');
    });
  });

  it('previous button is disabled on first page', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('prev-btn')).toBeDisabled();
    });
  });

  it('clicking next fetches second page', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('row-0')).toBeInTheDocument();
    });
    fireEvent.click(screen.getByTestId('next-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('page-info')).toHaveTextContent('11–20 of 50');
    });
  });

  it('page buttons render', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('page-1')).toBeInTheDocument();
    });
  });

  it('caches pages (no re-fetch on back)', async () => {
    render(<App />);
    await waitFor(() => expect(screen.getByTestId('row-0')).toBeInTheDocument());
    fireEvent.click(screen.getByTestId('next-btn'));
    await waitFor(() => expect(screen.getByTestId('page-info')).toHaveTextContent('11–20'));
    const callCount = fetchMock.mock.calls.length;
    fireEvent.click(screen.getByTestId('prev-btn'));
    await waitFor(() => expect(screen.getByTestId('page-info')).toHaveTextContent('1–10'));
    // Should not have made another fetch for page 1
    expect(fetchMock.mock.calls.length).toBe(callCount);
  });
});

