import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface Record {
  id: number;
  name: string;
  email: string;
  status: string;
}

interface PaginatedTableProps {
  apiUrl: string;
  limit: number;
}

export const PaginatedTable: React.FC<PaginatedTableProps> = ({ apiUrl, limit }) => {
  const [rows, setRows] = useState<Record[]>([]);
  const [page, setPage] = useState(1);
  const [totalCount, setTotalCount] = useState(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const cacheRef = useRef<Map<number, Record[]>>(new Map());

  const totalPages = Math.ceil(totalCount / limit) || 1;

  const fetchPage = useCallback(async (p: number) => {
    if (cacheRef.current.has(p)) {
      setRows(cacheRef.current.get(p)!);
      return;
    }
    setIsLoading(true);
    setError(null);
    try {
      const res = await fetch(`${apiUrl}?page=${p}&limit=${limit}`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const json = await res.json();
      cacheRef.current.set(p, json.data);
      setRows(json.data);
      setTotalCount(json.totalCount);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  }, [apiUrl, limit]);

  useEffect(() => {
    fetchPage(page);
  }, [page, fetchPage]);

  const rangeStart = (page - 1) * limit + 1;
  const rangeEnd = Math.min(page * limit, totalCount);

  const pageNumbers = Array.from({ length: totalPages }, (_, i) => i + 1);

  return (
    <div className="ptable">
      <div className="ptable__info">
        <span data-testid="page-info">
          {totalCount > 0 ? `${rangeStart}–${rangeEnd} of ${totalCount}` : 'No records'}
        </span>
      </div>

      <div className="ptable__wrapper">
        {isLoading && <div data-testid="loading-overlay" className="ptable__overlay" />}
        <table className="ptable__table">
          <thead>
            <tr>
              <th>Name</th>
              <th>Email</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody data-testid="table-body">
            {rows.map((row, i) => (
              <tr key={row.id} data-testid={`row-${i}`}>
                <td>{row.name}</td>
                <td>{row.email}</td>
                <td><span className={`ptable__status ptable__status--${row.status}`}>{row.status}</span></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="ptable__nav">
        <button data-testid="prev-btn" className="ptable__btn" disabled={page <= 1} onClick={() => setPage(p => p - 1)}>
          Previous
        </button>
        {pageNumbers.map(num => (
          <button
            key={num}
            data-testid={`page-${num}`}
            className={`ptable__btn${num === page ? ' ptable__btn--active' : ''}`}
            onClick={() => setPage(num)}
          >
            {num}
          </button>
        ))}
        <button data-testid="next-btn" className="ptable__btn" disabled={page >= totalPages} onClick={() => setPage(p => p + 1)}>
          Next
        </button>
      </div>
    </div>
  );
};
